@@ -0,0 +1,49 @@
+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Sales.History;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Handler (ID 30366) handles copying of Shopify-related fields.
+/// When copying sales documents, Shopify-related fields like Order Id and Order No should be cleared
+/// to avoid conflicts with invoice synchronization.
+/// </summary>
+codeunit 30366 "Shpfy Copy Document Handler"
+{
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopyFieldsFromOldSalesHeader', '', false, false)]
+    local procedure ClearShpfyFieldsOnAfterCopyFieldsFromOldSalesHeader(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; MoveNegLines: Boolean; IncludeHeader: Boolean; FromDocType: Enum "Sales Document Type From"; RecalculateLines: Boolean)
+    begin
+        // Clear Shopify-related fields when copying a sales document to ensure the new document
+        // is treated as a new document for Shopify synchronization purposes
+        ClearShpfyFieldsFromSalesHeader(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnCopySalesDocOnAfterTransferPostedInvoiceFields', '', false, false)]
+    local procedure ClearShpfyFieldsOnAfterTransferPostedInvoiceFields(var ToSalesHeader: Record "Sales Header"; FromSalesInvoiceHeader: Record "Sales Invoice Header"; var OldSalesHeader: Record "Sales Header")
+    begin
+        // Clear Shopify-related fields when copying from a posted invoice
+        ClearShpfyFieldsFromSalesHeader(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopyPostedShipment', '', false, false)]
+    local procedure ClearShpfyFieldsOnAfterCopyPostedShipment(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesShipmentHeader: Record "Sales Shipment Header")
+    begin
+        // Clear Shopify-related fields when copying from a posted shipment
+        ClearShpfyFieldsFromSalesHeader(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopyPostedReturnReceipt', '', false, false)]
+    local procedure ClearShpfyFieldsOnAfterCopyPostedReturnReceipt(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; ReturnReceiptHeader: Record "Return Receipt Header")
+    begin
+        // Clear Shopify-related fields when copying from a posted return receipt
+        ClearShpfyFieldsFromSalesHeader(ToSalesHeader);
+    end;
+
+    local procedure ClearShpfyFieldsFromSalesHeader(var SalesHeader: Record "Sales Header")
+    begin
+        SalesHeader."Shpfy Order Id" := 0;
+        SalesHeader."Shpfy Order No." := '';
+        SalesHeader."Shpfy Refund Id" := 0;
+    end;
+}

